-- Dumping structure for procedure tronbetong3.ct_save_nguyenlieu_unique_ma
DELIMITER //
CREATE PROCEDURE `ct_save_nguyenlieu_unique_ma`(
    IN p_inid INT,
    IN p_ma VARCHAR(63),
    IN p_ten VARCHAR(63),
    IN p_pl INT,
    IN p_doam DOUBLE,
    OUT p_id INT
)
BEGIN
    DECLARE dup_ma_id INT;
    
    -- Tìm bản ghi có các giá trị giống hệt
    SELECT id INTO dup_ma_id FROM ct_nguyenlieu WHERE ma = p_ma LIMIT 1;

    IF dup_ma_id IS NULL THEN
        -- Nếu không bị trung mã
        IF p_inid > 0 THEN
            UPDATE ct_nguyenlieu SET
                ma = p_ma,
                ten = p_ten,
                phanloai = p_pl,
                doam = p_doam
            WHERE id=p_inid;
            
            SET p_id = p_inid;
        ELSE
            VALUES (p_ma, p_ten, p_pl, p_doam);
            -- Lấy ID của bản ghi vừa thêm
            SET p_id = LAST_INSERT_ID();
        END IF;
    ELSE
        IF dup_ma_id = p_inid THEN
            UPDATE ct_nguyenlieu SET
                ma = p_ma,
                ten = p_ten,
                phanloai = p_pl,
                doam = p_doam
            WHERE id=p_inid;
            
            SET p_id = p_inid;
        ELSE
            SET p_id = -1;
        END IF;
    END IF;

    -- Trả về ID
    SELECT p_id AS id;
END//
DELIMITER ;

